202	void ProceduralContext::update_variable_state(slang::SourceLocation loc, VariableBits lvalue,
203			RTLIL::SigSpec unmasked_rvalue, RTLIL::SigSpec mask, bool blocking)
204	{
205		log_assert(lvalue.bitwidth() == (uint64_t)unmasked_rvalue.size());
206		log_assert(lvalue.bitwidth() == (uint64_t)mask.size());
207	
208		crop_zero_mask(mask, lvalue);
209		crop_zero_mask(mask, unmasked_rvalue);
210		crop_zero_mask(mask, mask);
211	
212		for (auto chunk : lvalue.chunks()) {
213			if (chunk.variable.kind == Variable::Static) {
214				if (blocking) {
215					if (seen_nonblocking_assignment.count(chunk.variable)) {
216						auto &diag = netlist.add_diag(diag::BlockingAssignmentAfterNonblocking, loc);
217						diag << chunk.variable.get_symbol()->name;
218						diag.addNote(diag::NotePreviousAssignment,
219								seen_nonblocking_assignment.at(chunk.variable));
220					} else {
221						seen_blocking_assignment[chunk.variable] = loc;
222					}
223				} else {
224					if (timing.kind == ProcessTiming::Initial) {
225						auto &diag = netlist.add_diag(diag::NonblockingAssignInInitialUnsupported, loc);
226						diag.addNote(diag::NoteIgnoreInitial, loc);
227						// We have issued the diagnostic, handle as blocking from
228						// this point onward.
229						blocking = true;
230					} else if (seen_blocking_assignment.count(chunk.variable)) {
231						auto &diag = netlist.add_diag(diag::NonblockingAssignmentAfterBlocking, loc);
232						diag << chunk.variable.get_symbol()->name;
233						diag.addNote(diag::NotePreviousAssignment,
234								seen_blocking_assignment.at(chunk.variable));
235					} else {
236						seen_nonblocking_assignment[chunk.variable] = loc;
237					}
238				}
239			} else if (chunk.variable.kind == Variable::Dummy) {
240				// Dummies are for graceful error handling and require
241				// no checking of blocking or nonblocking case
242			} else {
243				// This is expected to be an AST invariant -- we don't have a symbol
244				// to use here for the ast_invariant() helper, so it's a plain
245				// assert
246				log_assert(blocking);
247			}
248		}
249	
250		if (timing.kind == ProcessTiming::Initial) {
251			crop_undef_mask(mask, lvalue);
252			crop_undef_mask(mask, unmasked_rvalue);
253			crop_undef_mask(mask, mask);
254	
255			RTLIL::SigSpec &rvalue = unmasked_rvalue;
256	
257			if (!rvalue.is_fully_const()) {
258				netlist.add_diag(diag::ErrorNonconstantInitialEval, loc);
259				return;
260			}
261	
262			for (auto [base, size, chunk] : lvalue.chunk_spans()) {
263				switch (chunk.variable.kind) {
264				case Variable::Dummy:
265				case Variable::Invalid: continue;
266	
267				case Variable::Local:
268				case Variable::EscapeFlag:
269					for (uint64_t i = 0; i < size; i++) {
270						initial_locals_state[chunk[i]] = rvalue[(int)(base + i)].data;
271					}
272					break;
273				case Variable::Static: {
274					for (uint64_t i = 0; i < size; i++) {
275						netlist.initial_state[chunk[i]] = rvalue[(int)(base + i)].data;
276					}
277					const ast::Symbol &symbol = *chunk.variable.get_symbol();
278					if (netlist.is_inferred_memory(symbol)) {
279						bool big_endian = !symbol.as<ast::ValueSymbol>()
280												   .getType()
281												   .getFixedRange()
282												   .isDescending();
283						netlist.add_memory_init(netlist.id(symbol), chunk.base, big_endian,
284								rvalue.extract((int)base, (int)size).as_const());
285					}
286				} break;
287				default: log_abort();
288				}
289			}
290			return;
291		}
292	
293		current_case->actions.push_back(Case::Action{loc, lvalue, mask, unmasked_rvalue});
294	
295		if (mask.is_fully_ones()) {
296			// shortcut path to support initialization of automatic variables
297			// (evaluating the background value is unavailable on the first
298			// assignment)
299			vstate.set(lvalue, unmasked_rvalue);
300		} else {
301			RTLIL::SigSpec rvalue_background = vstate.evaluate(netlist, lvalue);
302			RTLIL::SigSpec rvalue = netlist.Bwmux(rvalue_background, unmasked_rvalue, mask);
303			vstate.set(lvalue, rvalue);
304		}
305	}
